    // released first.
    queue = new PriorityQueue<DumpArchiveEntry>(10,
            new Comparator<DumpArchiveEntry>() {
                public int compare(DumpArchiveEntry p, DumpArchiveEntry q) {
                    if (p.getOriginalName() == null || q.getOriginalName() == null) {
